import { isEmpty } from 'lodash-es';

import { _getCanvasColor as getCanvasColor } from '@dynatrace/strato-components/charts';

import { DEFAULT_ICON_BACKGROUND_COLOR } from '../../../constants.js';
import { Location } from '../../../types/location.js';
import { calculateHoveredColor } from '../../../utils/calculate-hovered-color.js';
import { defineColor } from '../../../utils/define-color.js';

interface ResolvedIconBackgroundColor {
  parsedBackgroundColor: string;
  parsedHoveredBackgroundColor: string;
}

export const resolveIconBackground = <T extends Location>(
  datapoint: T,
  backgroundColor: boolean | string | ((item: T) => string),
): ResolvedIconBackgroundColor => {
  let parsedBackgroundColor = getCanvasColor(DEFAULT_ICON_BACKGROUND_COLOR);
  let parsedHoveredBackgroundColor = calculateHoveredColor(
    parsedBackgroundColor,
  );

  if (typeof backgroundColor !== 'boolean') {
    const definedBgColor = defineColor(backgroundColor, datapoint);

    // check if the background color was successfully extracted out of the feature
    if (!isEmpty(definedBgColor)) {
      parsedBackgroundColor = getCanvasColor(
        definedBgColor,
        DEFAULT_ICON_BACKGROUND_COLOR,
      );
      parsedHoveredBackgroundColor = calculateHoveredColor(
        parsedBackgroundColor,
      );
    }
  }

  return {
    parsedBackgroundColor: parsedBackgroundColor,
    parsedHoveredBackgroundColor: parsedHoveredBackgroundColor,
  };
};
